package main

import (
	"net/http"

	"github.com/prometheus/client_golang/prometheus"
	"github.com/prometheus/client_golang/prometheus/promhttp"
)

var (
	userRequests = prometheus.NewCounterVec(
		prometheus.CounterOpts{
			Name: "user_requests_total",
		 Help: "Total number of requests per user.",
		},
		[]string{"user"},
	)
)

func init() {
	prometheus.MustRegister(userRequests)
}

func handleRequest(w http.ResponseWriter, r *http.Request) {
	user := r.URL.Query().Get("user")
	if user == "" {
		http.Error(w, "User parameter is required", http.StatusBadRequest)
		return
	}
	userRequests.WithLabelValues(user).Inc()
	w.Write([]byte("Request processed"))
}

func main() {
	http.HandleFunc("/metrics", promhttp.HandlerFor(prometheus.DefaultGatherer, promhttp.HandlerOpts{}))
	http.HandleFunc("/request", handleRequest)

	http.ListenAndServe(":8080", nil)
}